<?php require_once __DIR__.'/../../config.php'; require_once __DIR__.'/../../includes/Database.php'; require_once __DIR__.'/../../includes/RedisClient.php'; require_once __DIR__.'/../../includes/Monitor.php'; header('Content-Type: application/json; charset=utf-8'); header('Access-Control-Allow-Origin: *'); if($_SERVER['REQUEST_METHOD']==='OPTIONS'){http_response_code(204);exit;} $db=Database::getInstance();$ae=$db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='allow_public_api'")??'1';if($ae!=='1'){http_response_code(403);json_response(['error'=>'API disabled']);} $sites=$db->fetchAll("SELECT * FROM `sites` WHERE is_active=1 ORDER BY display_order ASC");$cs=Monitor::getCurrentStatus();$sm=Monitor::getSummary();$r=[];foreach($sites as $s){$st=$cs[$s['id']]??null;$ut=Monitor::getUptimeStats($s['id']);$r[]=['id'=>(int)$s['id'],'name'=>$s['name'],'url'=>$s['url'],'status'=>$st['status']??'unknown','http_code'=>$st['http_code']??null,'response_time'=>(int)($st['response_time']??0),'error_message'=>$st['error_message']??null,'ssl'=>$st['ssl']??null,'dns'=>$st['dns']??null,'checked_at'=>$st['checked_at']??null,'uptime'=>$ut];} json_response(['success'=>true,'summary'=>$sm,'sites'=>$r,'timestamp'=>date('Y-m-d H:i:s'),'version'=>APP_VERSION]);